<script setup lang="ts">import{Head,Link,router}from'@inertiajs/vue3';import AuthenticatedLayout from '@/Layouts/AuthenticatedLayout.vue';import AppButton from '@/Components/UI/AppButton.vue';import StatusBadge from '@/Components/UI/StatusBadge.vue';import Pagination from '@/Components/UI/Pagination.vue';interface Row{id:number;transaction_number:string;transaction_date:string;subtotal:string;status:string|{value:string};supplier:{name:string;company_name?:string};creator:{name:string}}interface P{data:Row[];links:{url:string|null;label:string;active:boolean}[];from:number;to:number;total:number}defineProps<{rows:P}>();const money=(v:string)=>new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',maximumFractionDigits:0}).format(Number(v));const sv=(s:Row['status'])=>typeof s==='string'?s:s.value;const finalize=(id:number)=>confirm('Finalisasi transaksi? Stok akan ditambah dan transaksi dikunci.')&&router.post(route('incoming.finalize',id));</script><template><Head title="Barang Masuk"/><AuthenticatedLayout><template #breadcrumb>Transaksi / Barang Masuk</template><div class="mb-6 flex items-end justify-between"><div><h1 class="page-title">Data Barang Masuk</h1><p class="page-subtitle">Finalisasi transaksi untuk memperbarui stok dan harga beli rata-rata.</p></div><Link :href="route('incoming.create')"><AppButton>＋ Barang Masuk</AppButton></Link></div><section class="panel"><div class="table-wrap"><table class="data-table"><thead><tr><th>Nomor Transaksi</th><th>Tanggal</th><th>Supplier</th><th>Subtotal</th><th>Dibuat Oleh</th><th>Status</th><th>Aksi</th></tr></thead><tbody><tr v-for="row in rows.data" :key="row.id"><td class="font-semibold text-sky-600">{{row.transaction_number}}</td><td>{{new Date(row.transaction_date).toLocaleDateString('id-ID')}}</td><td>{{row.supplier.company_name||row.supplier.name}}</td><td>{{money(row.subtotal)}}</td><td>{{row.creator.name}}</td><td><StatusBadge :status="sv(row.status)"/></td><td><button v-if="sv(row.status)==='draft'" 